mapper.select:
SELECT c.course_id, c.course_nm, c.course_desc, c.instructor_id, u.user_nm as instructor_nm,
       c.start_dt, c.end_dt, c.max_students, c.status, c.use_yn, c.reg_dt, c.upd_dt
FROM tb_course c
LEFT JOIN tb_user u ON c.instructor_id = u.user_id
WHERE 1=1

    AND c.status = #{status}


    AND c.instructor_id = #{instructorId}


    AND c.use_yn = #{useYn}

ORDER BY c.reg_dt DESC

mapper.delete:
UPDATE tb_course
SET use_yn = 'N', upd_dt = NOW()
WHERE course_id = #{courseId}

mapper.select:
SELECT COUNT(*)
FROM tb_course
WHERE 1=1

    AND status = #{status}


    AND use_yn = #{useYn}

mapper.update:
UPDATE tb_course
SET status = #{status}, upd_dt = NOW()
WHERE course_id = #{courseId}
